/**
 * n8n Function (Run Once for All Items)
 * Validate commission payloads; return original data + valid boolean
 * NOTE: order_id has been deprecated. ALL commission types must provide reference_id (UUID).
 */

const items = $input.all();

const UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

const ALLOWED_TYPES = new Set([
  'sale',
  'velocity',
  'monthly_consistency',
  'referral_overide',
  'tier_progression',
  'welcome_bonus',
]);

return items.map(({ json }) => {
  const data = { ...json };
  const errors = [];

  // commission_type
  const type = String(data.commission_type || '').trim();
  if (!ALLOWED_TYPES.has(type)) {
    errors.push(`Invalid commission_type: ${type}`);
  }

  // affiliate_id
  if (!data.affiliate_id) {
    errors.push('affiliate_id is required');
  } else if (!UUID_RE.test(String(data.affiliate_id))) {
    errors.push('affiliate_id must be a valid uuid');
  }

  // commission_amount
  if (data.commission_amount == null || data.commission_amount === '') {
    errors.push('commission_amount is required');
  } else if (!Number.isFinite(Number(data.commission_amount)) || Number(data.commission_amount) <= 0) {
    errors.push('commission_amount must be a positive number');
  }

  // reference_id (required for ALL commission types; replaces order_id)
  if (!data.reference_id) {
    errors.push('reference_id is required');
  } else if (!UUID_RE.test(String(data.reference_id))) {
    errors.push('reference_id must be a valid uuid');
  }

  return {
    json: {
      ...data,
      valid: errors.length === 0,
      errors,
    },
  };
});

// Inputs:
// - Main input ($input): array of rows from sales_attribution
// - "When Executed by Another Workflow": single claim JSON (or [JSON])

const salesData = $input.all().map(i => i.json);

// Read claim safely (object or [object])
const rawClaim = $('When Executed by Another Workflow').first().json;
const claim = Array.isArray(rawClaim) ? (rawClaim[0] || {}) : (rawClaim || {});

// --- helpers ---
const EPS = 0.01;
const toNum = (v) => (v == null || v === '' ? NaN : Number(v));
const isFiniteNum = (v) => Number.isFinite(toNum(v));
const norm = (v) => (v == null ? null : String(v).trim());

// Normalize the lookup key from claim (always reference_id now)
const referenceId = norm(claim.reference_id);

// Find attribution rows by treating row.reference_id || row.id || row.order_id as the same key
const rowsForRef = referenceId
  ? salesData.filter(r => {
      const keys = [norm(r.reference_id), norm(r.id), norm(r.order_id)];
      return keys.some(k => k && k === referenceId);
    })
  : [];

const reference_id_match = rowsForRef.length > 0;

// Pick the row that matches this affiliate (if any)
const affiliateId = norm(claim.affiliate_id);
const row = rowsForRef.find(r => norm(r.affiliate_id) === affiliateId) || null;

const affiliate_id_match = Boolean(row);
const reference_id_belongs_to_user = affiliate_id_match;

// commission_match: strict compare to affiliate_commission when present
let commission_match = null;
if (row) {
  const claimed  = toNum(claim.commission_amount);
  const expected = toNum(row.affiliate_commission);
  commission_match = (isFiniteNum(expected) && isFiniteNum(claimed))
    ? Math.abs(claimed - expected) < EPS
    : null; // unknown if attribution has no amount
}

// overall validity: reference exists + belongs to affiliate + (commission_match !== false)
// (null commission_match = unknown but acceptable; flip to === true if you want it strict)
const valid = Boolean(reference_id_match && reference_id_belongs_to_user && commission_match !== false);

// minimal echo of the matched attribution row
const matched_attribution = row
  ? {
      id: row.id,
      reference_id: row.reference_id ?? null,
      order_id: row.order_id ?? null,
      affiliate_id: row.affiliate_id,
      attribution_method: norm(row.attribution_method),
      affiliate_commission: row.affiliate_commission,
      attribution_data: (() => {
        const v = row.attribution_data;
        if (!v) return null;
        if (typeof v === 'object') return v;
        try { return JSON.parse(String(v)); } catch { return { raw: String(v) }; }
      })(),
      created_at: row.created_at,
      updated_at: row.updated_at,
      is_approved: row.is_approved ?? null,
    }
  : null;

// return ONE item
return [{
  json: {
    ...claim,
    valid,
    checks: {
      reference_id_match,
      affiliate_id_match,
      reference_id_belongs_to_user,
      commission_match,
    },
    matched_attribution,
  }
}];

// Inputs:
// - Main input ($input): array of velocity bonus rows (from velocity table/query)
// - "When Executed by Another Workflow": the commission claim JSON (or an array with one element)

const velocityRows = $input.all().map(i => i.json);

// Read claim safely whether it's a single JSON or an array with one item
let claimRaw = $('When Executed by Another Workflow').first().json;
const claim = Array.isArray(claimRaw) ? (claimRaw[0] || {}) : (claimRaw || {});

// --- helpers ---
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const EPS = 0.01;
const toNum = (v) => (v == null || v === '' ? NaN : Number(v));

// Find the velocity record by reference_id (maps to velocity.id)
const referenceId =
  claim?.reference_id && UUID_RE.test(String(claim.reference_id))
    ? String(claim.reference_id)
    : null;

const row = referenceId
  ? velocityRows.find(r => String(r.id) === referenceId) || null
  : null;

// reference_id_match: true if claim.reference_id matched a velocity row.id
const reference_id_match = Boolean(row);

// affiliate match
const affiliate_id_match = row
  ? String(row.affiliate_id || '') === String(claim.affiliate_id || '')
  : false;

// reference_id_belongs_to_user: same as affiliate match for velocity
const reference_id_belongs_to_user = affiliate_id_match;

// commission compare: bonus_amount vs commission_amount
let commission_match = null;
if (row) {
  const expected = toNum(row.bonus_amount);
  const claimed  = toNum(claim.commission_amount);
  commission_match =
    Number.isFinite(expected) &&
    Number.isFinite(claimed) &&
    Math.abs(claimed - expected) < EPS;
}

// overall validity (velocity):
// require reference id match + affiliate match + commission match
const valid = Boolean(reference_id_match && reference_id_belongs_to_user && commission_match === true);

// Minimal echo of the matched velocity record
const matched_attribution = row
  ? {
      id: row.id,
      affiliate_id: row.affiliate_id,
      bonus_type: row.bonus_type,
      referrals_count: row.referrals_count,
      bonus_amount: row.bonus_amount,
      window_start: row.window_start,
      window_end: row.window_end,
      achieved_at: row.achieved_at,
      created_at: row.created_at,
      velocity_referral_ids: row.velocity_referral_ids || [],
    }
  : null;

// return ONE item
return [{
  json: {
    ...claim,
    valid,
    checks: {
      reference_id_match,
      affiliate_id_match,
      reference_id_belongs_to_user,
      commission_match,
    },
    matched_attribution,
  }
}];

/**
 * n8n Function (Run Once for All Items)
 * Validate monthly_consistency commission against monthly_consistency_bonus rows.
 * Inputs:
 *  - Main input ($input): array of monthly_consistency_bonus rows
 *  - "When Executed by Another Workflow": claim JSON (or array with one item)
 * Output: one item -> { ...claim, valid, checks:{...}, matched_attribution }
 */

const bonusRows = $input.all().map(i => i.json);

// Claim may be a single JSON or an array with one element
const rawClaim = $('When Executed by Another Workflow').first().json;
const claim = Array.isArray(rawClaim) ? (rawClaim[0] || {}) : (rawClaim || {});

// Helpers
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const EPS = 0.01;
const toNum = (v) => (v == null || v === '' ? NaN : Number(v));

// Find bonus row by reference_id (claim.reference_id === row.id)
const referenceId =
  claim?.reference_id && UUID_RE.test(String(claim.reference_id))
    ? String(claim.reference_id)
    : null;

const row = referenceId
  ? bonusRows.find(r => String(r.id) === referenceId) || null
  : null;

// Checks
const reference_id_match = Boolean(row);

const affiliate_id_match = row
  ? String(row.affiliate_id || '') === String(claim.affiliate_id || '')
  : false;

const reference_id_belongs_to_user = affiliate_id_match;

// commission_match: bonus_amount vs claim.commission_amount
let commission_match = null;
if (row) {
  const expected = toNum(row.bonus_amount);
  const claimed  = toNum(claim.commission_amount);
  commission_match =
    Number.isFinite(expected) &&
    Number.isFinite(claimed) &&
    Math.abs(claimed - expected) < EPS;
}

// Overall validity: require ref match + affiliate match + commission match
const valid = Boolean(reference_id_match && reference_id_belongs_to_user && commission_match === true);

// Minimal echo of matched row
const matched_attribution = row ? {
  id: row.id,
  affiliate_id: row.affiliate_id,
  evaluation_year: row.evaluation_year,
  evaluation_month: row.evaluation_month,
  sales_at_evaluation: row.sales_at_evaluation,
  star_badge_at_evaluation: row.star_badge_at_evaluation,
  affiliate_status_at_evaluation: row.affiliate_status_at_evaluation,
  bonus_amount: row.bonus_amount,
  processed_at: row.processed_at,
  created_at: row.created_at,
  processing_mode: row.processing_mode,
} : null;

// Return ONE item
return [{
  json: {
    ...claim,
    valid,
    checks: {
      reference_id_match,
      affiliate_id_match,
      reference_id_belongs_to_user,
      commission_match,
    },
    matched_attribution,
  }
}];

// Inputs:
// - Main input ($input): array of l1_overide_bonus rows
// - "When Executed by Another Workflow": claim JSON (or array with one element)

const bonusRows = $input.all().map(i => i.json);

// Read claim (supports single JSON or [JSON])
const rawClaim = $('When Executed by Another Workflow').first().json;
const claim = Array.isArray(rawClaim) ? (rawClaim[0] || {}) : (rawClaim || {});

// Helpers
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const EPS = 0.01;
const toNum = (v) => (v == null || v === '' ? NaN : Number(v));

// Find the L1 override row by reference_id (claim.reference_id === row.id)
const referenceId =
  claim?.reference_id && UUID_RE.test(String(claim.reference_id))
    ? String(claim.reference_id)
    : null;

const row = referenceId
  ? bonusRows.find(r => String(r.id) === referenceId) || null
  : null;

// Checks
const reference_id_match = Boolean(row);

// affiliate must be the REFERRER (L1 override pays the referrer)
const affiliate_id_match = row
  ? String(row.referrer_id || '') === String(claim.affiliate_id || '')
  : false;

const reference_id_belongs_to_user = affiliate_id_match;

// commission must match referrer_bonus_amount exactly (±0.01)
let commission_match = null;
if (row) {
  const expected = toNum(row.referrer_bonus_amount);
  const claimed  = toNum(claim.commission_amount);
  commission_match =
    Number.isFinite(expected) &&
    Number.isFinite(claimed) &&
    Math.abs(claimed - expected) < EPS;
}

// Overall validity (referral_overide):
// require reference match + affiliate match + commission match
const valid = Boolean(reference_id_match && reference_id_belongs_to_user && commission_match === true);

// Minimal echo of matched row
const matched_attribution = row ? {
  id: row.id,
  referrer_id: row.referrer_id,
  referred_id: row.referred_id,
  total_referred_sales: row.total_referred_sales,
  referrer_bonus_amount: row.referrer_bonus_amount,
  milestone: row.milestone,
  milestone_achieved: row.milestone_achieved,             // informational only
  milestone_achieved_date: row.milestone_achieved_date,   // informational only
  created_at: row.created_at,
} : null;

// Return ONE item
return [{
  json: {
    ...claim,
    valid,
    checks: {
      reference_id_match,
      affiliate_id_match,
      reference_id_belongs_to_user,
      commission_match,
    },
    matched_attribution,
  }
}];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

// Inputs:
// - Main input ($input): array with affiliate row(s) (id, name, star_badge, commission_rate, created_at)
// - "When Executed by Another Workflow": claim JSON (or [JSON])

const rows = $input.all().map(i => i.json);

// Read claim whether it's a single JSON or an array with one item
const rawClaim = $('When Executed by Another Workflow').first().json;
const claim = Array.isArray(rawClaim) ? (rawClaim[0] || {}) : (rawClaim || {});

// Helpers
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

const toNum = (v) => (v == null || v === '' ? NaN : Number(v));
const isMYR = (c) => String(c || '').toUpperCase() === 'MYR';

function withinLastMonth(iso) {
  if (!iso) return false;
  const t = new Date(iso);
  if (isNaN(t.getTime())) return false;
  const now = new Date();
  const oneMonthAgo = new Date(now);
  oneMonthAgo.setMonth(now.getMonth() - 1);
  return t >= oneMonthAgo && t <= now;
}

// --- Resolve the target affiliate row by id (should equal both claim.reference_id and claim.affiliate_id) ---
const refId = String(claim.reference_id || '');
const affId = String(claim.affiliate_id || '');

const row = rows.find(r => String(r.id) === refId) || null;

// --- Checks ---
const reference_id_match =
  Boolean(row) && UUID_RE.test(refId) && String(row.id) === refId;

const affiliate_id_match =
  Boolean(row) && UUID_RE.test(affId) && String(row.id) === affId;

// For welcome_bonus, the reference belongs to the same user if affiliate_id matches
const reference_id_belongs_to_user = Boolean(affiliate_id_match);

// Commission must be exactly 10 MYR
const commission_match =
  toNum(claim.commission_amount) === 10 && isMYR(claim.currency);

// Affiliate must be newly created within the last month
const created_recent = row ? withinLastMonth(row.created_at) : false;

// Overall validity: all conditions must be true
const valid = Boolean(
  reference_id_match &&
  affiliate_id_match &&
  reference_id_belongs_to_user &&
  commission_match &&
  created_recent
);

// Minimal echo of matched row
const matched_attribution = row ? {
  id: row.id,
  name: row.name,
  star_badge: row.star_badge,
  commission_rate: row.commission_rate,
  created_at: row.created_at,
} : null;

// Return ONE item
return [{
  json: {
    ...claim,
    valid,
    checks: {
      reference_id_match,
      affiliate_id_match,
      reference_id_belongs_to_user,
      commission_match,
      created_recent,
    },
    matched_attribution,
  }
}];
